import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"标枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/标枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/标枪.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/标枪.md"};function p(b,e,l,i,_,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"标枪",tabindex:"-1"},[s("标枪 "),r("a",{class:"header-anchor",href:"#标枪","aria-label":'Permalink to "标枪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),o('<h1 id="标枪-1" tabindex="-1">标枪 <a class="header-anchor" href="#标枪-1" aria-label="Permalink to &quot;标枪&quot;">​</a></h1><p>标枪<br> 描述：你笑着骑着马，准备练习一下自己一向仁慈的枪法，忽然啊，海寇大爷一发标枪过来把你打下马。标枪是锁头的，盔甲是纸糊的，只有盾牌是铁打的。</p><p>价格：D+500<br> 分类：投掷武器<br> 武器伤害：3L<br> 武器特性：【高速1】【破甲1】<br> 伤害类型：物理-穿刺<br> 体积：特殊<br> 速射等级：【连射】<br> 装弹量：特殊<br> 射程：对应属性*5米</p><p>【重投掷/轻投掷】：该武器可以在购买时选择视为重投掷或是轻投掷武器。<br> 重投掷为巨型标枪，武器体积是【人物体积+2】，使用力量作为检定属性，射程额外提高力量附加*10米，同时获得【碾压】特性。<br> 体积小于4的单位无法选择重投掷。<br> ――<br> 轻投掷为小型标枪，武器体积固定为【2】，使用敏捷作为检定属性，投掷时可以选择额外消耗一个迅捷动作以增加物体出手的速度，让武器特性提供的高速从1变为4。</p><p>【标枪雨】：该标枪附赠一个用来装标枪的袋子，你可以从袋子里取出最多敏捷/力量取高把标枪，这是同时存在的上限数量，因此如同【无限子弹】一样计算 但这些标枪只能由你自行使用，其他人使用的场合只是普通的临时武器而已。</p><p>升级：C+1000<br> 支付后，标枪的武器伤害提升至11L，攻击将同时攻击落点范围内5米内的所有敌人，若是轻投掷武器，使增加出手速度无需消费迅捷动作。<br> 若是重投掷武器，则改为使破甲增加7点。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
